import{_ as o,c as r,a0 as c,o as a}from"./chunks/framework.B6JXc2q-.js";const h=JSON.parse('{"title":"Source 架构（Source Architecture）","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/source_architecture.md","filePath":"architecture/source_architecture.md"}'),s={name:"architecture/source_architecture.md"};function t(i,e,d,l,u,n){return a(),r("div",null,e[0]||(e[0]=[c(`<h1 id="source-架构-source-architecture" tabindex="-1">Source 架构（Source Architecture） <a class="header-anchor" href="#source-架构-source-architecture" aria-label="Permalink to &quot;Source 架构（Source Architecture）&quot;">​</a></h1><p>版本：v1.0 状态：正式架构文档 最后更新：2026-03-28</p><p>本文档定义 source 边界的职责、当前来源类型、与 playback / transport 的关系，以及插件在 source 体系中的位置。字段级规范见 <code>docs/spec/runtime_specification.md</code>。</p><hr><h2 id="_1-source-的统一定义" tabindex="-1">1. Source 的统一定义 <a class="header-anchor" href="#_1-source-的统一定义" aria-label="Permalink to &quot;1. Source 的统一定义&quot;">​</a></h2><p><strong>source</strong> 是&quot;媒体来源解析层&quot;。其职责是：给定一个播放请求（<code>MediaRequest</code>），解析并返回一个可播放的媒体流描述（<code>ResolvedMedia</code>）。</p><p>source 提供<strong>事实</strong>，不做<strong>策略决策</strong>：</p><ul><li>source 提供：流 URL、标题、来源标识、是否直播、是否需要代理</li><li>source 不决定：是否使用代理、投递方式、队列位置、播放模式</li></ul><p>所有 source 实现必须遵守统一接口：<code>SourcePlugin.resolve(request: MediaRequest) -&gt; ResolvedMedia</code>。</p><hr><h2 id="_2-当前四种正式-source-类型" tabindex="-1">2. 当前四种正式 source 类型 <a class="header-anchor" href="#_2-当前四种正式-source-类型" aria-label="Permalink to &quot;2. 当前四种正式 source 类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>来源标识</th><th>职责</th><th>代码位置</th></tr></thead><tbody><tr><td><code>direct_url</code></td><td>解析 HTTP/HTTPS 直链，不做任何转换</td><td><code>adapters/sources/direct_url_source_plugin.py</code></td></tr><tr><td><code>site_media</code></td><td>解析站点媒体（YouTube、Bilibili 等），通过 yt-dlp 或 MusicFree JS 插件提取流 URL</td><td><code>adapters/sources/site_media_source_plugin.py</code></td></tr><tr><td><code>jellyfin</code></td><td>解析 Jellyfin 资源，通过 Jellyfin API 获取流 URL</td><td><code>adapters/sources/jellyfin_source_plugin.py</code></td></tr><tr><td><code>local_library</code></td><td>解析本地媒体库中的曲目，返回本地文件或内置 HTTP 服务 URL</td><td><code>adapters/sources/local_library_source_plugin.py</code></td></tr></tbody></table><p>这四种类型是当前正式 source 类型的完整集合。新增 source 类型必须：</p><ol><li>实现 <code>SourcePlugin</code> 接口</li><li>在 <code>default_registry.py</code> 中注册</li><li>在 <code>api_v1_spec.md</code> 的 <code>source_hint</code> 允许值中声明</li></ol><p><code>source_hint = &quot;auto&quot;</code> 时，由 <code>SourceRegistry</code> 按注册顺序依次尝试匹配。</p><hr><h2 id="_3-source-与-playback-的边界" tabindex="-1">3. Source 与 Playback 的边界 <a class="header-anchor" href="#_3-source-与-playback-的边界" aria-label="Permalink to &quot;3. Source 与 Playback 的边界&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>播放请求 (MediaRequest)</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>[source 边界]</span></span>
<span class="line"><span>    SourceRegistry.get_plugin()  ← 选择匹配的插件</span></span>
<span class="line"><span>    SourcePlugin.resolve()       ← 解析，返回 ResolvedMedia</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>[playback 边界]</span></span>
<span class="line"><span>    DeliveryAdapter.prepare_plan()  ← 决定投递方式（直连/代理/relay）</span></span>
<span class="line"><span>    TransportRouter.dispatch()      ← 下发到设备</span></span></code></pre></div><p><strong>source 不得越过此边界：</strong></p><ul><li>source 不得访问 <code>DeviceRegistry</code> 或任何设备对象</li><li>source 不得做&quot;用代理还是直连&quot;的投递策略决定（<code>prefer_proxy</code> 是建议，不是命令）</li><li>source 不得修改播放队列或上下文</li><li>source 不得触发任何播放状态变更</li></ul><p><strong>playback 对 source 的约束：</strong></p><ul><li>playback 调用 source 的唯一入口是 <code>SourcePlugin.resolve()</code></li><li>playback 不得绕过 source 层直接拼装流 URL</li></ul><hr><h2 id="_4-source-与-transport-的关系" tabindex="-1">4. Source 与 Transport 的关系 <a class="header-anchor" href="#_4-source-与-transport-的关系" aria-label="Permalink to &quot;4. Source 与 Transport 的关系&quot;">​</a></h2><p>source 的输出（<code>ResolvedMedia</code>）经过 <code>DeliveryAdapter</code> 处理后，才能进入 transport 层。source 不直接与 transport 交互。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ResolvedMedia (source 输出)</span></span>
<span class="line"><span>    → DeliveryAdapter → PreparedStream / DeliveryPlan</span></span>
<span class="line"><span>    → TransportRouter → mina / miio transport</span></span></code></pre></div><p>source 提供的 <code>stream_url</code> 必须是 <code>http://</code> 或 <code>https://</code> 格式。非法 URL 会在 <code>DeliveryAdapter</code> 处被拒绝并抛出 <code>UndeliverableStreamError</code>，不会传入 transport 层。</p><hr><h2 id="_5-插件在-source-体系中的位置" tabindex="-1">5. 插件在 Source 体系中的位置 <a class="header-anchor" href="#_5-插件在-source-体系中的位置" aria-label="Permalink to &quot;5. 插件在 Source 体系中的位置&quot;">​</a></h2><p>系统中存在两类插件概念，必须明确区分：</p><h3 id="_5-1-source-plugin-来源插件-正式体系" tabindex="-1">5.1 Source Plugin（来源插件，正式体系） <a class="header-anchor" href="#_5-1-source-plugin-来源插件-正式体系" aria-label="Permalink to &quot;5.1 Source Plugin（来源插件，正式体系）&quot;">​</a></h3><ul><li>接口：<code>xiaomusic/core/source/source_plugin.py</code> 中的 <code>SourcePlugin</code> 抽象类</li><li>注册：<code>SourceRegistry</code>，通过 <code>default_registry.py</code> 注册内置四种</li><li>职责：实现 <code>resolve()</code> 方法，返回 <code>ResolvedMedia</code></li><li>这是 source 架构的正式扩展点</li></ul><h3 id="_5-2-musicfree-js-插件-外部媒体提供方-属于-site-media-source-的内部机制" tabindex="-1">5.2 MusicFree JS 插件（外部媒体提供方，属于 site_media source 的内部机制） <a class="header-anchor" href="#_5-2-musicfree-js-插件-外部媒体提供方-属于-site-media-source-的内部机制" aria-label="Permalink to &quot;5.2 MusicFree JS 插件（外部媒体提供方，属于 site_media source 的内部机制）&quot;">​</a></h3><ul><li>管理：<code>xiaomusic/managers/js_plugin_manager.py</code></li><li>职责：在 <code>site_media</code> source 插件内部，调用第三方 MusicFree JS 脚本解析特定站点</li><li><strong>这不是 source 体系的扩展点</strong>，是 <code>site_media</code> source 的内部实现细节</li></ul><h3 id="_5-3-python-exec-插件-命令扩展-不属于-source-体系" tabindex="-1">5.3 Python exec 插件（命令扩展，不属于 source 体系） <a class="header-anchor" href="#_5-3-python-exec-插件-命令扩展-不属于-source-体系" aria-label="Permalink to &quot;5.3 Python exec 插件（命令扩展，不属于 source 体系）&quot;">​</a></h3><ul><li>管理：<code>xiaomusic/plugin.py</code></li><li>职责：扩展自然语言命令处理，不涉及媒体来源解析</li><li><strong>不属于 source 体系</strong></li></ul><hr><h2 id="_6-source-不允许承担的职责" tabindex="-1">6. Source 不允许承担的职责 <a class="header-anchor" href="#_6-source-不允许承担的职责" aria-label="Permalink to &quot;6. Source 不允许承担的职责&quot;">​</a></h2><p>以下职责明确不属于 source 边界，不得在 source 实现中出现：</p><ul><li>播放模式决策（随机、循环等）</li><li>队列管理（上一首、下一首计算）</li><li>设备状态读取</li><li>播放上下文（context）的创建或修改</li><li>revision 生成或 play_session_id 分配</li><li>relay session 的创建</li><li>对 transport 层的直接调用</li></ul><hr><h2 id="_7-新增-source-的约束" tabindex="-1">7. 新增 Source 的约束 <a class="header-anchor" href="#_7-新增-source-的约束" aria-label="Permalink to &quot;7. 新增 Source 的约束&quot;">​</a></h2><p>新增 source 类型时，必须满足：</p><ol><li>继承 <code>SourcePlugin</code> 抽象类，实现 <code>name</code> 属性和 <code>resolve()</code> 方法</li><li><code>resolve()</code> 只返回 <code>ResolvedMedia</code>，不产生副作用</li><li>在 <code>default_registry.py</code> 中以确定性顺序注册</li><li>在 <code>api_v1_spec.md</code> 的 <code>source_hint</code> 允许值列表中声明</li><li>来源标识（<code>source</code> 字段）必须属于四种正式类型之一，或在 API 契约中新增声明</li></ol><hr><h2 id="_8-相关文档" tabindex="-1">8. 相关文档 <a class="header-anchor" href="#_8-相关文档" aria-label="Permalink to &quot;8. 相关文档&quot;">​</a></h2><table tabindex="0"><thead><tr><th>文档</th><th>职责</th></tr></thead><tbody><tr><td><code>docs/spec/runtime_specification.md</code></td><td><code>MediaRequest</code>、<code>ResolvedMedia</code> 等数据模型的字段定义</td></tr><tr><td><code>docs/architecture/system_overview.md</code></td><td>source 在系统九个一级边界中的位置</td></tr><tr><td><code>docs/api/api_v1_spec.md</code></td><td><code>source_hint</code> 允许值、<code>POST /api/v1/play</code> 契约</td></tr><tr><td><code>docs/architecture/unified_playback_model.md</code></td><td>播放上下文、队列、播放模式的概念定义</td></tr></tbody></table>`,47)]))}const _=o(s,[["render",t]]);export{h as __pageData,_ as default};
